import re
from dataclasses import dataclass

UNKNOWN_SPEAKER = "UNKNOWN"
TURN_GAP_THRESHOLD_SEC = 0.8
LONG_PAUSE_THRESHOLD_SEC = 4.0

SHORT_TURN_MAX_WORDS = 10
MEDIUM_TURN_MIN_WORDS = 11
MEDIUM_TURN_MAX_WORDS = 29
LONG_TURN_MIN_WORDS = 30

LOW_ENGAGEMENT_TALK_RATIO_PCT = 10.0
LOW_ENGAGEMENT_MIN_TURNS = 2
WITHDRAWN_WPM_THRESHOLD = 80.0
WITHDRAWN_AVG_WORDS_PER_TURN_THRESHOLD = 15.0
PRESSURED_WPM_THRESHOLD = 160.0
HIGH_DYSFLUENCY_RATE_THRESHOLD = 0.05
RUMINATION_SELF_REFERENCE_RATE_THRESHOLD = 0.15
RUMINATION_ABSOLUTIST_RATE_THRESHOLD = 0.02
FACILITATOR_DEPENDENT_RATIO_THRESHOLD = 0.8

EPSILON = 1e-9

DYSFLUENCY_SINGLE_TOKENS = {"um", "uh", "like"}
DYSFLUENCY_MULTIWORD_PHRASES = (
    ("you", "know"),
    ("i", "mean"),
    ("sort", "of"),
    ("kind", "of"),
)

SELF_REFERENCE_TOKENS = {"i", "me", "my", "myself"}
ABSOLUTIST_TOKENS = {
    "never",
    "always",
    "everyone",
    "nobody",
    "everything",
    "nothing",
    "impossible",
    "completely",
    "totally",
    "literally",
}

NEGATION_TOKENS = {
    "no",
    "not",
    "never",
    "none",
    "nothing",
    "nobody",
    "neither",
    "nor",
    "dont",
    "don't",
    "cant",
    "can't",
    "wont",
    "won't",
    "didnt",
    "didn't",
    "isnt",
    "isn't",
    "arent",
    "aren't",
    "wasnt",
    "wasn't",
    "werent",
    "weren't",
}

EMOTIONAL_TOKENS = {
    "sad",
    "happy",
    "angry",
    "anxious",
    "afraid",
    "scared",
    "upset",
    "stressed",
    "worried",
    "depressed",
    "lonely",
    "tired",
    "hurt",
    "frustrated",
    "overwhelmed",
    "calm",
    "good",
    "bad",
    "well",
}

PRESENT_TENSE_HINT_TOKENS = {
    "am",
    "is",
    "are",
    "do",
    "does",
    "have",
    "has",
    "feel",
    "feeling",
    "think",
    "know",
    "like",
}

PAST_TENSE_HINT_TOKENS = {
    "was",
    "were",
    "did",
    "had",
    "felt",
    "thought",
    "knew",
    "liked",
}

WORD_RE = re.compile(r"[A-Za-z']+")


@dataclass
class Segment:
    speaker: str
    start: float
    end: float
    text: str


@dataclass
class Turn:
    speaker: str
    start: float
    end: float
    text: str


def safe_div(num, den):
    if den <= 0:
        return 0.0
    return num / den


def duration_minutes(seconds):
    return seconds / 60.0


def count_words(text):
    return len(WORD_RE.findall((text or "").lower()))


def tokenize_words(text):
    return WORD_RE.findall((text or "").lower())


def count_multiword_phrases(tokens, phrase):
    if not tokens or not phrase or len(phrase) > len(tokens):
        return 0
    count = 0
    phrase_len = len(phrase)
    for i in range(len(tokens) - phrase_len + 1):
        if tuple(tokens[i:i + phrase_len]) == tuple(phrase):
            count += 1
    return count


def count_dysfluencies(tokens):
    single_count = sum(1 for t in tokens if t in DYSFLUENCY_SINGLE_TOKENS)
    phrase_count = sum(count_multiword_phrases(tokens, phrase) for phrase in DYSFLUENCY_MULTIWORD_PHRASES)
    return single_count + phrase_count


def count_self_references(tokens):
    return sum(1 for t in tokens if t in SELF_REFERENCE_TOKENS)


def count_absolutist_words(tokens):
    return sum(1 for t in tokens if t in ABSOLUTIST_TOKENS)


def count_negations(tokens):
    return sum(1 for t in tokens if t in NEGATION_TOKENS)


def count_emotional_words(tokens):
    return sum(1 for t in tokens if t in EMOTIONAL_TOKENS)


def count_question_marks(text):
    return (text or "").count("?")


def estimate_tense_ratio(tokens):
    present_count = 0
    past_count = 0

    for token in tokens:
        if token in PRESENT_TENSE_HINT_TOKENS:
            present_count += 1
        if token in PAST_TENSE_HINT_TOKENS or token.endswith("ed"):
            past_count += 1

    return safe_div(float(past_count), float(present_count))


def extract_raw_segments(payload):
    turns = payload.get("turns", [])
    if not isinstance(turns, list):
        return []
    return turns


def collect_declared_speakers(raw_segments):
    seen = set()
    speakers = []

    for item in raw_segments:
        if not isinstance(item, dict):
            continue
        speaker = item.get("speaker")
        if isinstance(speaker, str):
            s = speaker.strip()
            if s and s != UNKNOWN_SPEAKER and s not in seen:
                seen.add(s)
                speakers.append(s)

    return speakers


def clean_segments(raw_segments):
    cleaned = []
    last_known_speaker = None

    for item in raw_segments:
        if not isinstance(item, dict):
            continue

        try:
            start = float(item.get("start", 0))
            end = float(item.get("end", 0))
        except (TypeError, ValueError):
            continue

        text_raw = item.get("text", "")
        speaker_raw = item.get("speaker", "")

        if not isinstance(text_raw, str) or not isinstance(speaker_raw, str):
            continue

        speaker = speaker_raw.strip()
        text = text_raw.strip()

        if end <= start:
            continue

        if speaker != UNKNOWN_SPEAKER and speaker:
            last_known_speaker = speaker
        elif speaker == UNKNOWN_SPEAKER:
            if last_known_speaker is None:
                continue
            speaker = last_known_speaker
        else:
            continue

        cleaned.append(Segment(speaker=speaker, start=start, end=end, text=text))

    cleaned.sort(key=lambda s: (s.start, s.end))
    return cleaned


def build_turns(segments, gap_threshold_sec=TURN_GAP_THRESHOLD_SEC):
    if not segments:
        return []

    turns = []
    current = Turn(
        speaker=segments[0].speaker,
        start=segments[0].start,
        end=segments[0].end,
        text=segments[0].text.strip(),
    )

    for seg in segments[1:]:
        same_speaker = seg.speaker == current.speaker
        gap = seg.start - current.end

        if same_speaker and gap <= gap_threshold_sec:
            current.end = max(current.end, seg.end)
            if seg.text:
                current.text = (current.text + " " + seg.text).strip()
        else:
            turns.append(current)
            current = Turn(
                speaker=seg.speaker,
                start=seg.start,
                end=seg.end,
                text=seg.text.strip(),
            )

    turns.append(current)
    turns.sort(key=lambda t: (t.start, t.end))
    return turns


def session_bounds(turns):
    if not turns:
        return 0.0, 0.0
    return turns[0].start, max(t.end for t in turns)


def participation_arc_for_speaker(speaker_turns, session_start, session_end):
    arc = {"early": 0, "mid": 0, "late": 0}
    total_duration = session_end - session_start

    if total_duration <= 0:
        if speaker_turns:
            arc["early"] = len(speaker_turns)
        return arc

    one_third = total_duration / 3.0
    early_end = session_start + one_third
    mid_end = session_start + 2.0 * one_third

    for turn in speaker_turns:
        x = turn.start
        if x < early_end:
            arc["early"] += 1
        elif x < mid_end:
            arc["mid"] += 1
        else:
            arc["late"] += 1

    return arc


def compute_global_turn_features(turns):
    features = {}

    for i, turn in enumerate(turns):
        duration_sec = max(0.0, turn.end - turn.start)
        tokens = tokenize_words(turn.text)
        word_count = float(len(tokens))

        dys_count = float(count_dysfluencies(tokens))
        self_ref_count = float(count_self_references(tokens))
        abs_count = float(count_absolutist_words(tokens))

        wpm = safe_div(word_count, duration_minutes(duration_sec))

        silence_after = 0.0
        if i + 1 < len(turns):
            silence_after = max(0.0, turns[i + 1].start - turn.end)

        prev_diff_speaker_gap = -1.0
        if i > 0 and turns[i - 1].speaker != turn.speaker:
            prev_diff_speaker_gap = max(0.0, turn.start - turns[i - 1].end)

        features[i] = {
            "duration_sec": duration_sec,
            "word_count": word_count,
            "dys_count": dys_count,
            "self_ref_count": self_ref_count,
            "abs_count": abs_count,
            "wpm": wpm,
            "dys_rate": safe_div(dys_count, word_count),
            "self_ref_rate": safe_div(self_ref_count, word_count),
            "abs_rate": safe_div(abs_count, word_count),
            "silence_after": silence_after,
            "prev_diff_speaker_gap": prev_diff_speaker_gap,
        }

    return features


def speaker_turn_indices(turns):
    by_speaker = {}
    for i, t in enumerate(turns):
        by_speaker.setdefault(t.speaker, []).append(i)
    return by_speaker


def compute_metrics_for_speaker(
    speaker,
    turns,
    turn_indices,
    features,
    session_start,
    session_end,
    total_session_talk_time_sec,
):
    s_turns = [turns[i] for i in turn_indices]

    turn_count = len(s_turns)
    total_talk_time = sum(features[i]["duration_sec"] for i in turn_indices)
    total_words = sum(features[i]["word_count"] for i in turn_indices)

    session_duration_sec = max(0.0, session_end - session_start)

    engagement = {
        "turn_count": turn_count,
        "total_talk_time_sec": round(total_talk_time, 3),
        "talk_ratio_pct": round(100.0 * safe_div(total_talk_time, total_session_talk_time_sec), 3),
        "total_word_count": int(total_words),
        "avg_turn_duration_sec": round(safe_div(total_talk_time, turn_count), 3),
        "avg_words_per_turn": round(safe_div(total_words, turn_count), 3),
        "turns_per_minute": round(safe_div(turn_count, duration_minutes(session_duration_sec)), 3),
    }

    short_turn_count = 0
    medium_turn_count = 0
    long_turn_count = 0

    dysfluency_count = 0.0
    self_reference_count = 0.0
    absolutist_count = 0.0

    for i in turn_indices:
        wc = features[i]["word_count"]
        if wc <= SHORT_TURN_MAX_WORDS:
            short_turn_count += 1
        elif MEDIUM_TURN_MIN_WORDS <= wc <= MEDIUM_TURN_MAX_WORDS:
            medium_turn_count += 1
        elif wc >= LONG_TURN_MIN_WORDS:
            long_turn_count += 1

        dysfluency_count += features[i]["dys_count"]
        self_reference_count += features[i]["self_ref_count"]
        absolutist_count += features[i]["abs_count"]

    speech_pattern = {
        "wpm": round(safe_div(total_words, duration_minutes(total_talk_time)), 3),
        "short_turn_count": short_turn_count,
        "medium_turn_count": medium_turn_count,
        "long_turn_count": long_turn_count,
        "dysfluency_count": int(dysfluency_count),
        "dysfluency_rate": round(safe_div(dysfluency_count, total_words), 6),
        "self_reference_count": int(self_reference_count),
        "self_reference_rate": round(safe_div(self_reference_count, total_words), 6),
        "absolutist_word_count": int(absolutist_count),
        "absolutist_rate": round(safe_div(absolutist_count, total_words), 6),
    }

    first_turn_time = s_turns[0].start if s_turns else 0.0
    last_turn_time = s_turns[-1].start if s_turns else 0.0

    long_pause_count = 0
    max_silence_after = 0.0
    for i in turn_indices:
        silence_after = features[i]["silence_after"]
        if silence_after > LONG_PAUSE_THRESHOLD_SEC:
            long_pause_count += 1
            max_silence_after = max(max_silence_after, silence_after)

    arc = participation_arc_for_speaker(s_turns, session_start, session_end)

    response_latencies = [
        features[i]["prev_diff_speaker_gap"]
        for i in turn_indices
        if features[i]["prev_diff_speaker_gap"] >= 0.0
    ]

    temporal = {
        "first_turn_time_sec": round(first_turn_time, 3),
        "last_turn_time_sec": round(last_turn_time, 3),
        "long_pause_count": long_pause_count,
        "max_silence_after_turn_sec": round(max_silence_after, 3),
        "participation_arc": arc,
        "avg_response_latency_sec": round(
            safe_div(sum(response_latencies), float(len(response_latencies))), 3
        ),
    }

    return {
        "engagement": engagement,
        "speech_pattern": speech_pattern,
        "temporal": temporal,
    }


def compute_flags_for_speaker(
    speaker,
    metrics,
    speaker_indices,
    turns,
    facilitator,
):
    engagement = metrics["engagement"]
    speech = metrics["speech_pattern"]
    temporal = metrics["temporal"]

    talk_ratio_pct = float(engagement["talk_ratio_pct"])
    turn_count = int(engagement["turn_count"])
    wpm = float(speech["wpm"])
    avg_words_per_turn = float(engagement["avg_words_per_turn"])
    dys_rate = float(speech["dysfluency_rate"])
    self_rate = float(speech["self_reference_rate"])
    abs_rate = float(speech["absolutist_rate"])

    flag_low_engagement = (
        talk_ratio_pct < LOW_ENGAGEMENT_TALK_RATIO_PCT or turn_count < LOW_ENGAGEMENT_MIN_TURNS
    )
    flag_withdrawn = wpm < WITHDRAWN_WPM_THRESHOLD and avg_words_per_turn < WITHDRAWN_AVG_WORDS_PER_TURN_THRESHOLD
    flag_pressured = wpm > PRESSURED_WPM_THRESHOLD
    flag_high_dysfluency = dys_rate > HIGH_DYSFLUENCY_RATE_THRESHOLD
    flag_rumination = (
        self_rate > RUMINATION_SELF_REFERENCE_RATE_THRESHOLD
        and abs_rate > RUMINATION_ABSOLUTIST_RATE_THRESHOLD
    )
    flag_disengaged_late = (
        int(temporal["participation_arc"]["late"]) == 0
        and int(temporal["participation_arc"]["early"]) > 0
    )

    responses_to_facilitator = 0
    for i in speaker_indices:
        if i > 0 and turns[i - 1].speaker == facilitator:
            responses_to_facilitator += 1

    response_ratio = safe_div(float(responses_to_facilitator), float(turn_count))
    flag_facilitator_dependent = turn_count > 0 and response_ratio >= FACILITATOR_DEPENDENT_RATIO_THRESHOLD

    return {
        "flag_low_engagement": bool(flag_low_engagement),
        "flag_withdrawn": bool(flag_withdrawn),
        "flag_pressured": bool(flag_pressured),
        "flag_high_dysfluency": bool(flag_high_dysfluency),
        "flag_rumination": bool(flag_rumination),
        "flag_disengaged_late": bool(flag_disengaged_late),
        "flag_facilitator_dependent": bool(flag_facilitator_dependent),
    }


def inline_flags_for_text(text):
    flags = []
    tokens = tokenize_words(text)

    if count_negations(tokens) > 0:
        flags.append("negation")
    if count_self_references(tokens) > 0:
        flags.append("self_reference")
    if count_dysfluencies(tokens) > 0:
        flags.append("dysfluency")
    if count_absolutist_words(tokens) > 0:
        flags.append("absolutist")
    if count_emotional_words(tokens) > 0:
        flags.append("emotional_language")
    if count_question_marks(text) > 0:
        flags.append("question")

    return flags


def build_dialogue_for_speaker(speaker, turns):
    dialogue = []
    i = 0
    turn_index = 1

    while i < len(turns):
        turn = turns[i]
        if turn.speaker != speaker:
            i += 1
            continue

        start_idx = i
        end_idx = i
        while end_idx + 1 < len(turns) and turns[end_idx + 1].speaker == speaker:
            end_idx += 1

        merged_text = " ".join(
            t.text.strip() for t in turns[start_idx:end_idx + 1] if t.text.strip()
        ).strip()
        merged_word_count = count_words(merged_text)

        if end_idx > start_idx:
            prompt_obj = None
        else:
            prev_idx = start_idx - 1
            if prev_idx >= 0 and turns[prev_idx].speaker != speaker:
                prompt_obj = {
                    "speaker": turns[prev_idx].speaker,
                    "text": turns[prev_idx].text,
                }
            else:
                prompt_obj = None

        dialogue.append(
            {
                "turn_index": turn_index,
                "prompt": prompt_obj,
                "response": {
                    "text": merged_text,
                    "word_count": merged_word_count,
                },
                "inline_flags": inline_flags_for_text(merged_text),
            }
        )

        turn_index += 1
        i = end_idx + 1

    return dialogue


def compute_content_signals_for_speaker(speaker_turns):
    if not speaker_turns:
        return {
            "emotional_word_rate": 0.0,
            "negation_rate": 0.0,
            "question_rate": 0.0,
            "tense_ratio": 0.0,
            "vocabulary_diversity": 0.0,
        }

    all_text = " ".join(t.text for t in speaker_turns)
    tokens = tokenize_words(all_text)
    total_words = float(len(tokens))
    unique_words = float(len(set(tokens)))

    emotional_word_rate = safe_div(float(count_emotional_words(tokens)), total_words)
    negation_rate = safe_div(float(count_negations(tokens)), total_words)
    question_turns = sum(1 for t in speaker_turns if count_question_marks(t.text) > 0)
    question_rate = safe_div(float(question_turns), float(len(speaker_turns)))
    tense_ratio = estimate_tense_ratio(tokens)
    vocabulary_diversity = safe_div(unique_words, total_words)

    return {
        "emotional_word_rate": round(emotional_word_rate, 6),
        "negation_rate": round(negation_rate, 6),
        "question_rate": round(question_rate, 6),
        "tense_ratio": round(tense_ratio, 6),
        "vocabulary_diversity": round(vocabulary_diversity, 6),
    }


def slim_metrics_for_output(full_metrics):
    engagement = full_metrics["engagement"]
    speech = full_metrics["speech_pattern"]
    temporal = full_metrics["temporal"]

    arc = temporal.get("participation_arc", {"early": 0, "mid": 0, "late": 0})
    early = float(arc.get("early", 0))
    late = float(arc.get("late", 0))
    participation_drop = safe_div(max(0.0, early - late), early) if early > 0 else 0.0

    return {
        "engagement": {
            "turn_count": int(engagement["turn_count"]),
            "talk_ratio_pct": float(engagement["talk_ratio_pct"]),
            "avg_words_per_turn": float(engagement["avg_words_per_turn"]),
            "total_talk_time_sec": float(engagement["total_talk_time_sec"]),
        },
        "speech_pattern": {
            "wpm": float(speech["wpm"]),
            "dysfluency_rate": float(speech["dysfluency_rate"]),
            "self_reference_rate": float(speech["self_reference_rate"]),
            "absolutist_rate": float(speech["absolutist_rate"]),
        },
        "temporal": {
            "long_pause_count": int(temporal["long_pause_count"]),
            "avg_response_latency_sec": float(temporal["avg_response_latency_sec"]),
            "participation_drop": round(participation_drop, 6),
        },
        "content_signals": {
            "emotional_word_rate": 0.0,
            "negation_rate": 0.0,
            "question_rate": 0.0,
            "tense_ratio": 0.0,
            "vocabulary_diversity": 0.0,
        },
    }


def local_key_reasons_for_turn(feature):
    reasons = []
    wc = int(feature["word_count"])

    if wc <= SHORT_TURN_MAX_WORDS and wc > 0:
        reasons.append("very_short_turn")

    if feature["dys_rate"] > HIGH_DYSFLUENCY_RATE_THRESHOLD:
        reasons.append("high_dysfluency")

    if feature["wpm"] > PRESSURED_WPM_THRESHOLD:
        reasons.append("pressured_speech")

    if (
        feature["self_ref_rate"] > RUMINATION_SELF_REFERENCE_RATE_THRESHOLD
        and feature["abs_rate"] > RUMINATION_ABSOLUTIST_RATE_THRESHOLD
    ):
        reasons.append("rumination_language")

    return reasons


def select_key_turns(speaker, turns, speaker_indices, features):
    if not speaker_indices:
        return []

    selected = {}

    sorted_by_wc = sorted(
        speaker_indices,
        key=lambda idx: (features[idx]["word_count"], turns[idx].end - turns[idx].start),
        reverse=True,
    )

    for idx in sorted_by_wc[:3]:
        if features[idx]["word_count"] > 0:
            selected.setdefault(idx, []).append("longest_turn")

    for idx in speaker_indices:
        reasons = local_key_reasons_for_turn(features[idx])
        if reasons:
            selected.setdefault(idx, []).extend(reasons)

    key_turns = []
    for idx in sorted(selected.keys(), key=lambda i: turns[i].start):
        turn = turns[idx]
        reason_values = selected[idx]
        unique_reasons = []
        seen = set()
        for r in reason_values:
            if r not in seen:
                seen.add(r)
                unique_reasons.append(r)

        key_turns.append(
            {
                "start": round(turn.start, 3),
                "end": round(turn.end, 3),
                "text": turn.text,
                "word_count": int(features[idx]["word_count"]),
                "reason": ",".join(unique_reasons),
            }
        )

    return key_turns


def zero_metrics():
    return {
        "engagement": {
            "turn_count": 0,
            "total_talk_time_sec": 0.0,
            "talk_ratio_pct": 0.0,
            "total_word_count": 0,
            "avg_turn_duration_sec": 0.0,
            "avg_words_per_turn": 0.0,
            "turns_per_minute": 0.0,
        },
        "speech_pattern": {
            "wpm": 0.0,
            "short_turn_count": 0,
            "medium_turn_count": 0,
            "long_turn_count": 0,
            "dysfluency_count": 0,
            "dysfluency_rate": 0.0,
            "self_reference_count": 0,
            "self_reference_rate": 0.0,
            "absolutist_word_count": 0,
            "absolutist_rate": 0.0,
        },
        "temporal": {
            "first_turn_time_sec": 0.0,
            "last_turn_time_sec": 0.0,
            "long_pause_count": 0,
            "max_silence_after_turn_sec": 0.0,
            "participation_arc": {"early": 0, "mid": 0, "late": 0},
            "avg_response_latency_sec": 0.0,
        },
    }


def false_flags():
    return {
        "flag_low_engagement": False,
        "flag_withdrawn": False,
        "flag_pressured": False,
        "flag_high_dysfluency": False,
        "flag_rumination": False,
        "flag_disengaged_late": False,
        "flag_facilitator_dependent": False,
    }


def build_speaker_outputs(turns, facilitator, all_speakers):
    if not all_speakers:
        return []

    features = compute_global_turn_features(turns)
    by_speaker = speaker_turn_indices(turns)
    session_start, session_end = session_bounds(turns)
    total_session_talk_time_sec = sum(f["duration_sec"] for f in features.values())

    speakers_sorted = sorted(set(all_speakers))
    results = []

    for speaker in speakers_sorted:
        idxs = by_speaker.get(speaker, [])
        s_turns = [turns[i] for i in idxs]

        if idxs:
            full_metrics = compute_metrics_for_speaker(
                speaker=speaker,
                turns=turns,
                turn_indices=idxs,
                features=features,
                session_start=session_start,
                session_end=session_end,
                total_session_talk_time_sec=total_session_talk_time_sec,
            )
        else:
            full_metrics = zero_metrics()

        total_talk_time = float(full_metrics["engagement"]["total_talk_time_sec"])
        if total_talk_time <= 0.0 + EPSILON:
            full_metrics = zero_metrics()
            flags = false_flags()
        else:
            flags = compute_flags_for_speaker(
                speaker=speaker,
                metrics=full_metrics,
                speaker_indices=idxs,
                turns=turns,
                facilitator=facilitator,
            )

        metrics = slim_metrics_for_output(full_metrics)
        metrics["content_signals"] = compute_content_signals_for_speaker(s_turns)

        results.append(
            {
                "speaker_id": speaker,
                "total_duration_sec": round(total_talk_time, 3),
                "metrics": metrics,
                "flags": flags,
                "dialogue": build_dialogue_for_speaker(speaker, turns),
                "key_turns": select_key_turns(speaker, turns, idxs, features),
            }
        )

    return results


def build_transcript(cleaned_segments):
    return [
        {
            "speaker": seg.speaker,
            "text": seg.text,
            "start": round(seg.start, 3),
            "end": round(seg.end, 3),
        }
        for seg in cleaned_segments
    ]


# -----------------------------
# Make entry point
# -----------------------------
payload = input if isinstance(input, dict) else {}
facilitator = payload.get("facilitator", "SPEAKER_AI")

raw_segments = extract_raw_segments(payload)
declared_speakers = collect_declared_speakers(raw_segments)
cleaned_segments = clean_segments(raw_segments)

if not cleaned_segments:
    return {
        "students": [],
        "transcript": [],
        "speaker_durations": {},
        "error": "No valid turns found in input['turns']"
    }

turns = build_turns(cleaned_segments, gap_threshold_sec=TURN_GAP_THRESHOLD_SEC)
resolved_speakers = sorted({t.speaker for t in turns})
all_speakers = sorted(set(declared_speakers) | set(resolved_speakers))

students = build_speaker_outputs(
    turns=turns,
    facilitator=facilitator,
    all_speakers=all_speakers,
)

speaker_durations = {
    speaker: round(
        sum((t.end - t.start) for t in turns if t.speaker == speaker),
        3
    )
    for speaker in all_speakers
}

transcript = build_transcript(cleaned_segments)

return {
    "students": students,
    "transcript": transcript,
    "speaker_durations": speaker_durations,
    "session_duration_sec": round(float(payload.get("duration", 0) or 0), 3),
    "turn_count_input": len(raw_segments),
    "turn_count_processed": len(turns),
}
